import{_ as e,c as s,a,o as n}from"./app-CEcM0piI.js";const l={};function t(d,i){return n(),s("div",null,i[0]||(i[0]=[a(`<p>Git GUI 图形界面工具 Git Bash 窗口，相当于小型的Linux，能够执行Linux命令</p><p>Git为了和Linux命令区分开，在每个Git命令前都会有git</p><p>要首先配置用户名和邮箱，通过这些信息区分是谁修改的（邮箱不要求是必须存在的邮箱）</p><h1 id="配置" tabindex="-1"><a class="header-anchor" href="#配置"><span>配置</span></a></h1><p>配置用户信息</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>git config --global user.name &quot;用户名&quot;</span></span>
<span class="line"><span>git config --global user.email &quot;邮箱地址&quot;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><p>如果用户名或邮箱地址字段有空格需要用双引号括起来，如果没有空格不用双引号也可以 省略（Local）：本地配置，只对本地仓库有效 --global：全局配置，所有仓库生效 --system：系统配置，对所有用户生效</p><p>保存用户名和密码</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>git config --global credential.helper store</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>查看配置信息</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>git config --global user.name     #查看用户名</span></span>
<span class="line"><span>git config --global user.email    #查看邮箱</span></span>
<span class="line"><span>git config --global --list        #查看所有配置信息</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="为常用指令配置别名" tabindex="-1"><a class="header-anchor" href="#为常用指令配置别名"><span>为常用指令配置别名</span></a></h2><p>有些常用指令参数非常多，每次都要输入很多参数，可以使用别名解决</p><ol><li>打开用户目录，创建<code>.bashrc</code>文件。有的windows无法创建以.开头的文件，可以使用git bash用linux的touch命令创建</li><li>在<code>.bashrc</code>文件中输入以下内容</li></ol><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>#用于输出git提交日志</span></span>
<span class="line"><span>alias git-log=&#39;git log --pretty=oneline --all --graph --abbrev-commit&#39;</span></span>
<span class="line"><span>#用于输出当前目录所有文件及基本信息</span></span>
<span class="line"><span>alias ll=&#39;ls -al&#39;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h1 id="分区" tabindex="-1"><a class="header-anchor" href="#分区"><span>分区</span></a></h1><p>git分为三个区：工作区（Working DIrectory）、暂存区（Staging Area/index）、本地仓库（Local Repository）</p><ul><li>工作区：电脑上能看到的文件夹就是工作区</li><li>暂存区：用于保存即将提交到GIt仓库的修改内容，是在Git进行版本控制时非常重要的区域</li><li>本地仓库：通过git init命令创建的仓库，包含完整的项目历史和元数据，是git存储代码和版本信息的主要位置 当修改完工作区的文件后需要将它们添加到暂存区（git add），然后再将暂存区的修改提交到本地仓库中（git commit）</li></ul><h2 id="git中的文件状态" tabindex="-1"><a class="header-anchor" href="#git中的文件状态"><span>Git中的文件状态</span></a></h2><p><strong>存在以下四种状态</strong></p><ol><li>未跟踪Untrack 新创建的还没有被git管理起来的文件</li><li>未修改Unmodified 被git管理起来，但文件的内容没有发生变化（没有被修改过）的文件</li><li>已修改Modified 修改了文件但还没有添加到暂存区里面</li><li>已暂存Staged 已经修改后并且已经添加到了暂存区域内的文件</li></ol>`,21)]))}const c=e(l,[["render",t]]),p=JSON.parse('{"path":"/tools/git/1/","title":"1、简介","lang":"zh-CN","frontmatter":{"title":"1、简介","createTime":"2025/06/18 21:08:06","permalink":"/tools/git/1/"},"readingTime":{"minutes":2.19,"words":656},"git":{"createdTime":1750599657000,"updatedTime":1750599657000,"contributors":[{"name":"pink","username":"pink","email":"pinkdopeybug@163.com","commits":1,"avatar":"https://avatars.githubusercontent.com/pink?v=4","url":"https://github.com/pink"}]},"filePathRelative":"notes/工具/Git/1、简介.md","headers":[]}');export{c as comp,p as data};
